import { useState } from "react";

const LOGO_SRC = "data:image/jpeg;base64,";
const HERBIE_SRC = "data:image/webp;base64,";

const styles = `
  @import url('https://fonts.googleapis.com/css2?family=Syne:wght@600;700;800&family=Inter:wght@400;500;600&family=JetBrains+Mono:wght@400;500&display=swap');

  :root {
    --blue:   #4d7cff;
    --teal:   #2ee8c8;
    --navy:   #0e1120;
    --card:   #161b2e;
    --surface:#1e2540;
    --border: #2a3356;
    --white:  #eef1ff;
    --muted:  #8b95b8;
    --black:  #090c18;
    --green:  #2ecc8c;
    --amber:  #f5a623;
    --red:    #ff5c5c;
  }

  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

  body {
    font-family: 'Inter', sans-serif;
    background: var(--navy);
    color: var(--white);
    min-height: 100vh;
    line-height: 1.6;
    -webkit-font-smoothing: antialiased;
  }

  /* ── Nav ── */
  .nav {
    position: sticky; top: 0; z-index: 100;
    background: rgba(14,17,32,0.96);
    border-bottom: 1px solid var(--border);
    padding: 0 2rem;
    display: flex; align-items: center; justify-content: space-between;
    height: 62px;
    backdrop-filter: blur(12px);
  }
  .nav-brand {
    display: flex; align-items: center; gap: 10px;
    font-family: 'Syne', sans-serif;
    font-size: 22px; font-weight: 800; letter-spacing: -0.5px;
    color: var(--white);
  }
  .nav-brand img { width: 34px; height: 34px; object-fit: contain; border-radius: 6px; }
  .nav-links { display: flex; align-items: center; gap: 2px; }
  .nav-btn {
    background: none; border: none; cursor: pointer;
    font-family: 'Inter', sans-serif; font-size: 14px; font-weight: 500;
    color: var(--muted); padding: 6px 14px; border-radius: 6px; transition: all 0.15s;
  }
  .nav-btn:hover { background: rgba(255,255,255,0.06); color: var(--white); }
  .nav-btn.active { color: var(--white); background: rgba(255,255,255,0.08); }
  .sign-btn {
    background: var(--blue); color: #fff; border: none; cursor: pointer;
    font-family: 'Inter', sans-serif; font-size: 13px; font-weight: 600;
    padding: 7px 18px; border-radius: 6px; transition: all 0.15s; margin-left: 10px;
  }
  .sign-btn:hover { background: #6b94ff; }
  .sign-btn.out { background: transparent; color: var(--muted); border: 1px solid var(--border); }
  .sign-btn.out:hover { color: var(--white); border-color: rgba(255,255,255,0.25); background: rgba(255,255,255,0.05); }
  .user-chip { display: flex; align-items: center; gap: 8px; font-size: 14px; color: var(--white); font-family: 'Inter', sans-serif; }
  .avatar {
    width: 30px; height: 30px; border-radius: 50%; background: var(--blue);
    display: flex; align-items: center; justify-content: center;
    font-size: 12px; font-weight: 700; color: #fff; flex-shrink: 0;
  }

  /* ── Home Hero ── */
  .home-hero {
    min-height: calc(100vh - 62px);
    display: flex; flex-direction: column; align-items: center; justify-content: center;
    padding: 4rem 2rem 2rem; text-align: center;
    background:
      radial-gradient(ellipse 60% 60% at 50% 40%, rgba(77,124,255,0.14), transparent),
      radial-gradient(ellipse 40% 40% at 80% 20%, rgba(46,232,200,0.07), transparent);
  }
  .home-logo-wrap {
    width: 96px; height: 96px; border-radius: 22px; overflow: hidden;
    margin-bottom: 1.75rem;
    box-shadow: 0 0 0 1px var(--border), 0 20px 60px rgba(77,124,255,0.28);
    animation: logoFloat 4s ease-in-out infinite;
  }
  @keyframes logoFloat {
    0%, 100% { transform: translateY(0px); }
    50% { transform: translateY(-8px); }
  }
  .home-logo-wrap img { width: 100%; height: 100%; object-fit: cover; }
  .home-hero h1 {
    font-family: 'Syne', sans-serif;
    font-size: clamp(56px, 10vw, 100px);
    font-weight: 800; letter-spacing: -3px; line-height: 1.0;
    color: var(--white); margin-bottom: 0.6rem;
  }
  .home-hero h1 .gradient-text {
    background: linear-gradient(135deg, var(--teal) 0%, var(--blue) 100%);
    -webkit-background-clip: text; -webkit-text-fill-color: transparent;
    background-clip: text;
  }
  .home-tagline {
    font-size: clamp(15px, 2.2vw, 20px); color: var(--muted);
    font-style: italic; margin-bottom: 2rem; letter-spacing: 0.2px;
  }
  .home-description {
    font-size: 16px; color: #a0aac8; max-width: 560px;
    line-height: 1.75; margin-bottom: 2.5rem;
  }
  .home-ctas { display: flex; gap: 12px; justify-content: center; flex-wrap: wrap; margin-bottom: 5rem; }
  .cta-primary {
    background: var(--blue); color: #fff; border: none; cursor: pointer;
    font-family: 'Inter', sans-serif; font-size: 15px; font-weight: 600;
    padding: 13px 28px; border-radius: 10px; transition: all 0.2s;
    display: flex; align-items: center; gap: 8px;
    box-shadow: 0 4px 20px rgba(77,124,255,0.4);
  }
  .cta-primary:hover { background: #6b94ff; transform: translateY(-2px); box-shadow: 0 8px 28px rgba(77,124,255,0.5); }
  .cta-secondary {
    background: transparent; color: var(--white); border: 1px solid var(--border);
    cursor: pointer; font-family: 'Inter', sans-serif; font-size: 15px; font-weight: 500;
    padding: 13px 28px; border-radius: 10px; transition: all 0.2s;
  }
  .cta-secondary:hover { border-color: rgba(255,255,255,0.3); background: rgba(255,255,255,0.05); transform: translateY(-2px); }
  .home-features {
    display: grid; grid-template-columns: repeat(3, 1fr);
    gap: 16px; max-width: 860px; width: 100%;
  }
  @media (max-width: 680px) { .home-features { grid-template-columns: 1fr; } }
  .feature-card {
    background: var(--card); border: 1px solid var(--border);
    border-radius: 14px; padding: 1.5rem; text-align: left; transition: border-color 0.2s;
  }
  .feature-card:hover { border-color: rgba(77,124,255,0.4); }
  .feature-icon { font-size: 28px; margin-bottom: 12px; display: block; }
  .feature-title { font-family: 'Syne', sans-serif; font-size: 17px; font-weight: 700; color: var(--white); margin-bottom: 8px; }
  .feature-desc { font-size: 13px; color: var(--muted); line-height: 1.6; }

  /* ── Modals ── */
  .modal-overlay {
    position: fixed; inset: 0; z-index: 300;
    background: rgba(9,12,24,0.82);
    display: flex; align-items: center; justify-content: center;
    animation: fadeIn 0.15s ease; padding: 1rem; backdrop-filter: blur(6px);
  }
  @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }
  @keyframes slideUp { from { transform: translateY(14px); opacity: 0; } to { transform: translateY(0); opacity: 1; } }
  .modal {
    background: var(--card); border: 1px solid var(--border);
    border-radius: 14px; padding: 2rem; width: 420px; max-width: 100%;
    animation: slideUp 0.2s ease; box-shadow: 0 24px 64px rgba(0,0,0,0.5);
  }
  .modal.wide { width: 540px; }
  .modal.tall { max-height: 90vh; overflow-y: auto; width: 560px; }
  .modal h2 { font-family: 'Syne', sans-serif; font-size: 24px; font-weight: 700; color: var(--white); margin-bottom: 4px; }
  .modal-sub { font-size: 14px; color: var(--muted); margin-bottom: 1.5rem; line-height: 1.5; }
  .field { margin-bottom: 1rem; }
  .field label { font-size: 12px; font-weight: 600; color: var(--muted); display: block; margin-bottom: 6px; letter-spacing: 0.5px; text-transform: uppercase; }
  .field input, .field textarea, .field select {
    width: 100%; padding: 10px 13px; border: 1px solid var(--border); border-radius: 8px;
    font-family: 'Inter', sans-serif; font-size: 14px; background: var(--surface);
    outline: none; transition: border 0.15s; color: var(--white);
  }
  .field textarea { resize: vertical; min-height: 90px; line-height: 1.6; }
  .field select { cursor: pointer; }
  .field select option { background: var(--surface); color: var(--white); }
  .field input:focus, .field textarea:focus, .field select:focus { border-color: var(--blue); box-shadow: 0 0 0 3px rgba(77,124,255,0.18); }
  .modal-actions { display: flex; gap: 8px; margin-top: 1.5rem; }
  .btn-primary { flex: 1; background: var(--blue); color: #fff; border: none; cursor: pointer; padding: 11px; border-radius: 8px; font-family: 'Inter', sans-serif; font-size: 14px; font-weight: 600; transition: all 0.15s; }
  .btn-primary:hover { background: #6b94ff; }
  .btn-secondary { flex: 1; background: transparent; border: 1px solid var(--border); cursor: pointer; padding: 11px; border-radius: 8px; font-family: 'Inter', sans-serif; font-size: 14px; transition: all 0.15s; color: var(--muted); }
  .btn-secondary:hover { border-color: rgba(255,255,255,0.25); color: var(--white); }
  .error-msg { font-size: 12px; color: var(--red); margin-top: 8px; }

  /* ── Tags ── */
  .tag { display: inline-block; font-size: 11px; font-weight: 600; padding: 3px 8px; border-radius: 4px; text-transform: uppercase; letter-spacing: 0.6px; font-family: 'Inter', sans-serif; }
  .tag.green  { background: rgba(46,204,140,0.18); color: #3ddba0; border: 1px solid rgba(46,204,140,0.35); }
  .tag.amber  { background: rgba(245,166,35,0.18); color: #f5a623; border: 1px solid rgba(245,166,35,0.35); }
  .tag.gray   { background: rgba(139,149,184,0.15); color: #b0bcd8; border: 1px solid rgba(139,149,184,0.3); }
  .tag.indigo { background: rgba(77,124,255,0.18); color: #7da4ff; border: 1px solid rgba(77,124,255,0.35); }
  .pill-row { display: flex; align-items: center; gap: 6px; flex-wrap: wrap; }

  /* ── Page shells ── */
  .page { max-width: 880px; margin: 0 auto; padding: 3rem 2rem 5rem; }
  .page-header { margin-bottom: 2.5rem; }
  .page-header h1 { font-family: 'Syne', sans-serif; font-size: clamp(28px, 4vw, 44px); line-height: 1.15; color: var(--white); font-weight: 800; margin-bottom: 8px; letter-spacing: -0.5px; }
  .page-header p { font-size: 15px; color: var(--muted); line-height: 1.6; }

  /* ── Slide viewer ── */
  .slide-viewer { background: var(--black); border-radius: 12px; border: 1px solid var(--border); overflow: hidden; }
  .slide-canvas { aspect-ratio: 16/9; position: relative; overflow: hidden; }
  .slide-inner { width: 100%; height: 100%; }
  .slide-controls { display: flex; align-items: center; justify-content: space-between; padding: 10px 16px; border-top: 1px solid var(--border); background: var(--card); }
  .slide-nav-btn { background: transparent; border: 1px solid var(--border); cursor: pointer; padding: 6px 14px; border-radius: 6px; font-size: 13px; font-family: 'Inter', sans-serif; color: var(--white); transition: all 0.15s; font-weight: 500; }
  .slide-nav-btn:hover:not(:disabled) { background: var(--surface); border-color: rgba(255,255,255,0.2); }
  .slide-nav-btn:disabled { opacity: 0.3; cursor: default; }
  .slide-dots { display: flex; gap: 6px; align-items: center; }
  .dot { width: 7px; height: 7px; border-radius: 50%; background: var(--border); border: none; cursor: pointer; transition: all 0.2s; padding: 0; }
  .dot.active { background: var(--teal); width: 20px; border-radius: 4px; }
  .slide-thumbs { display: flex; gap: 8px; padding: 10px 14px; border-top: 1px solid var(--border); overflow-x: auto; background: var(--card); }
  .thumb { flex-shrink: 0; width: 80px; aspect-ratio: 16/9; border-radius: 5px; overflow: hidden; cursor: pointer; border: 2px solid transparent; transition: border 0.15s; position: relative; }
  .thumb.active { border-color: var(--teal); }

  /* ── Deck action buttons ── */
  .deck-actions-row { display: flex; gap: 8px; padding: 10px 16px; border-top: 1px solid var(--border); background: var(--card); justify-content: flex-end; }
  .deck-download-btn { background: rgba(46,232,200,0.1); color: var(--teal); border: 1px solid rgba(46,232,200,0.3); cursor: pointer; padding: 7px 14px; border-radius: 7px; font-family: 'Inter', sans-serif; font-size: 12px; font-weight: 600; transition: all 0.15s; display: flex; align-items: center; gap: 5px; }
  .deck-download-btn:hover { background: rgba(46,232,200,0.2); border-color: var(--teal); }

  /* ── Comment panel ── */
  .comment-panel { border-top: 1px solid var(--border); background: var(--card); }
  .comment-panel-header { display: flex; align-items: center; justify-content: space-between; padding: 10px 16px 6px; }
  .comment-panel-header h4 { font-size: 12px; font-weight: 600; color: var(--muted); text-transform: uppercase; letter-spacing: 0.6px; }
  .comment-list { max-height: 160px; overflow-y: auto; padding: 0 16px 8px; display: flex; flex-direction: column; gap: 8px; }
  .comment-item { display: flex; gap: 10px; align-items: flex-start; }
  .comment-body { background: var(--surface); border: 1px solid var(--border); border-radius: 8px; padding: 8px 12px; flex: 1; }
  .comment-author { font-size: 12px; font-weight: 600; color: var(--white); margin-bottom: 3px; }
  .comment-text { font-size: 13px; color: var(--muted); line-height: 1.55; }
  .comment-input-row { display: flex; gap: 8px; padding: 8px 16px 14px; align-items: center; }
  .comment-input-row input { flex: 1; padding: 8px 12px; border: 1px solid var(--border); border-radius: 7px; font-family: 'Inter', sans-serif; font-size: 13px; outline: none; background: var(--surface); color: var(--white); }
  .comment-input-row input:focus { border-color: var(--blue); }
  .comment-input-row input::placeholder { color: var(--muted); }
  .comment-send-btn { background: var(--blue); color: #fff; border: none; cursor: pointer; padding: 8px 16px; border-radius: 7px; font-size: 13px; font-family: 'Inter', sans-serif; white-space: nowrap; font-weight: 600; }
  .comment-send-btn:hover { background: #6b94ff; }
  .comment-mode-bar { padding: 7px 16px; background: rgba(245,166,35,0.1); border-top: 1px solid rgba(245,166,35,0.25); font-size: 13px; color: var(--amber); display: flex; align-items: center; gap: 8px; }
  .mode-toggle { display: flex; background: var(--surface); border: 1px solid var(--border); border-radius: 7px; overflow: hidden; }
  .mode-tab { border: none; background: none; cursor: pointer; padding: 6px 16px; font-size: 13px; font-family: 'Inter', sans-serif; color: var(--muted); transition: all 0.15s; font-weight: 500; }
  .mode-tab.active { background: var(--blue); color: #fff; }
  .mode-tab:not(:last-child) { border-right: 1px solid var(--border); }

  /* ── Search / Reviewer ── */
  .search-bar { position: relative; margin-bottom: 1.5rem; }
  .search-bar input { width: 100%; padding: 11px 16px 11px 44px; border: 1px solid var(--border); border-radius: 10px; font-family: 'Inter', sans-serif; font-size: 14px; background: var(--card); outline: none; transition: border 0.15s; color: var(--white); }
  .search-bar input:focus { border-color: var(--blue); box-shadow: 0 0 0 3px rgba(77,124,255,0.18); }
  .search-bar input::placeholder { color: var(--muted); }
  .search-icon { position: absolute; left: 14px; top: 50%; transform: translateY(-50%); color: var(--muted); font-size: 16px; pointer-events: none; }
  .deck-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(250px, 1fr)); gap: 14px; }
  .deck-card { background: var(--card); border-radius: 12px; border: 1px solid var(--border); overflow: hidden; cursor: pointer; transition: border-color 0.2s, transform 0.15s; }
  .deck-card:hover { border-color: rgba(255,255,255,0.2); transform: translateY(-2px); }
  .deck-thumb { aspect-ratio: 16/9; overflow: hidden; position: relative; }
  .deck-info { padding: 12px 14px; }
  .deck-title { font-weight: 600; font-size: 14px; margin-bottom: 6px; color: var(--white); }
  .deck-meta { font-size: 12px; color: var(--muted); display: flex; align-items: center; gap: 6px; }
  .back-btn { background: none; border: none; cursor: pointer; font-family: 'Inter', sans-serif; font-size: 14px; font-weight: 500; color: var(--muted); padding: 0; margin-bottom: 1.5rem; display: flex; align-items: center; gap: 6px; transition: color 0.15s; }
  .back-btn:hover { color: var(--white); }
  .reviewer-badge { background: rgba(77,124,255,0.2); color: #7da4ff; font-size: 11px; font-weight: 600; padding: 3px 10px; border-radius: 20px; border: 1px solid rgba(77,124,255,0.35); }

  /* ── Idea form ── */
  .visibility-toggle { display: flex; gap: 10px; margin-bottom: 1.5rem; }
  .vis-btn { flex: 1; padding: 13px 14px; border-radius: 10px; border: 1px solid var(--border); background: var(--card); cursor: pointer; text-align: left; transition: all 0.15s; font-family: 'Inter', sans-serif; }
  .vis-btn:hover { border-color: rgba(255,255,255,0.2); }
  .vis-btn.selected { border-color: var(--blue); background: rgba(77,124,255,0.12); }
  .vis-btn-label { font-size: 14px; font-weight: 600; color: var(--white); margin-bottom: 3px; }
  .vis-btn-desc { font-size: 12px; color: var(--muted); }
  .feedback-type-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 10px; margin-bottom: 1.25rem; }
  .feedback-type-btn { padding: 13px 14px; border-radius: 10px; border: 1px solid var(--border); background: var(--card); cursor: pointer; text-align: left; transition: all 0.15s; font-family: 'Inter', sans-serif; }
  .feedback-type-btn:hover { border-color: rgba(255,255,255,0.2); }
  .feedback-type-btn.selected { border-color: var(--teal); background: rgba(46,232,200,0.08); }
  .ftb-icon { display: flex; align-items: center; margin-bottom: 8px; width: 22px; height: 22px; }
  .ftb-name { font-size: 13px; font-weight: 600; color: var(--white); display: block; margin-bottom: 3px; }
  .ftb-desc { font-size: 12px; color: var(--muted); line-height: 1.4; display: block; }
  .feedback-type-label { font-size: 12px; font-weight: 600; color: var(--muted); letter-spacing: 0.5px; text-transform: uppercase; margin-bottom: 8px; display: block; }
  .idea-form { background: var(--card); border-radius: 14px; border: 1px solid var(--border); padding: 1.75rem; }
  .form-field { margin-bottom: 1.25rem; }
  .form-field label { display: block; font-size: 12px; font-weight: 600; color: var(--muted); letter-spacing: 0.5px; text-transform: uppercase; margin-bottom: 7px; }
  .form-field input, .form-field textarea, .form-field select { width: 100%; padding: 10px 13px; border: 1px solid var(--border); border-radius: 8px; font-family: 'Inter', sans-serif; font-size: 14px; background: var(--surface); outline: none; transition: border 0.15s; color: var(--white); line-height: 1.5; }
  .form-field input::placeholder, .form-field textarea::placeholder { color: var(--muted); }
  .form-field input:focus, .form-field textarea:focus, .form-field select:focus { border-color: var(--blue); box-shadow: 0 0 0 3px rgba(77,124,255,0.18); }
  .form-field textarea { resize: vertical; min-height: 110px; line-height: 1.6; }
  .form-field select { cursor: pointer; }
  .form-field select option { background: var(--surface); color: var(--white); }
  .submit-btn { background: var(--blue); color: #fff; border: none; cursor: pointer; padding: 13px 28px; border-radius: 10px; font-family: 'Inter', sans-serif; font-size: 15px; font-weight: 600; transition: all 0.15s; width: 100%; }
  .submit-btn:hover:not(:disabled) { background: #6b94ff; }
  .submit-btn:disabled { opacity: 0.4; cursor: not-allowed; }
  .success-card { background: rgba(46,204,140,0.12); border-radius: 10px; border: 1px solid rgba(46,204,140,0.35); padding: 1.25rem; text-align: center; margin-top: 1rem; animation: slideUp 0.3s ease; }
  .success-card h3 { font-family: 'Syne', sans-serif; font-size: 20px; color: var(--green); margin-bottom: 5px; font-weight: 700; }
  .success-card p { font-size: 14px; color: #6ddba8; }
  .locked-gate { background: var(--card); border-radius: 14px; border: 1px solid var(--border); padding: 3.5rem 2rem; text-align: center; }
  .lock-icon { font-size: 44px; margin-bottom: 1rem; display: block; }
  .locked-gate h3 { font-family: 'Syne', sans-serif; font-size: 26px; color: var(--white); margin-bottom: 8px; font-weight: 700; }
  .locked-gate p { font-size: 15px; color: var(--muted); margin-bottom: 1.5rem; }

  /* ── Idea cards ── */
  .ideas-list { margin-top: 2rem; }
  .ideas-list h3 { font-family: 'Syne', sans-serif; font-size: 24px; margin-bottom: 1rem; color: var(--white); font-weight: 700; border-bottom: 1px solid var(--border); padding-bottom: 10px; }
  .idea-card { background: var(--card); border-radius: 12px; border: 1px solid var(--border); padding: 1.1rem 1.25rem; margin-bottom: 12px; transition: border-color 0.15s; }
  .idea-card:hover { border-color: rgba(255,255,255,0.15); }
  .idea-card-top { display: flex; align-items: flex-start; justify-content: space-between; gap: 8px; margin-bottom: 8px; }
  .idea-card-title { font-weight: 600; font-size: 16px; margin-bottom: 3px; color: var(--white); line-height: 1.3; }
  .idea-card-meta { font-size: 12px; color: var(--muted); margin-bottom: 8px; }
  .idea-card-body { font-size: 14px; color: #c4cce8; line-height: 1.65; }
  .category-badge { display: inline-block; font-size: 11px; font-weight: 600; padding: 2px 8px; border-radius: 4px; margin-right: 4px; }
  .card-action-row { display: flex; gap: 6px; }
  .share-icon-btn { background: none; border: 1px solid var(--border); cursor: pointer; padding: 5px 11px; border-radius: 6px; font-size: 12px; font-family: 'Inter', sans-serif; color: var(--muted); transition: all 0.15s; display: flex; align-items: center; gap: 4px; white-space: nowrap; font-weight: 500; }
  .share-icon-btn:hover { border-color: rgba(255,255,255,0.25); color: var(--white); }
  .edit-icon-btn { background: rgba(77,124,255,0.1); border: 1px solid rgba(77,124,255,0.35); cursor: pointer; padding: 5px 11px; border-radius: 6px; font-size: 12px; font-family: 'Inter', sans-serif; color: #7da4ff; transition: all 0.15s; display: flex; align-items: center; gap: 4px; white-space: nowrap; font-weight: 500; }
  .edit-icon-btn:hover { background: rgba(77,124,255,0.2); border-color: var(--blue); color: var(--white); }

  /* ── AI feedback ── */
  .ai-feedback { margin-top: 12px; padding: 13px 15px; border-radius: 10px; border-left: 3px solid; display: flex; gap: 12px; align-items: flex-start; }
  .ai-feedback.fantastic    { background: rgba(77,124,255,0.12); border-color: var(--blue); }
  .ai-feedback.constructive { background: rgba(46,232,200,0.1);  border-color: var(--teal); }
  .ai-feedback.friendly     { background: rgba(245,166,35,0.1);  border-color: var(--amber); }
  .ai-feedback.personal     { background: rgba(255,100,120,0.1); border-color: #ff6478; }
  .ai-bot-img { width: 40px; height: 40px; object-fit: contain; flex-shrink: 0; border-radius: 6px; }
  .ai-feedback-content { flex: 1; }
  .ai-feedback-label { font-size: 11px; font-weight: 700; text-transform: uppercase; letter-spacing: 0.6px; margin-bottom: 5px; display: flex; align-items: center; gap: 5px; font-family: 'Inter', sans-serif; }
  .ai-feedback.fantastic    .ai-feedback-label { color: #7da4ff; }
  .ai-feedback.constructive .ai-feedback-label { color: var(--teal); }
  .ai-feedback.friendly     .ai-feedback-label { color: var(--amber); }
  .ai-feedback.personal     .ai-feedback-label { color: #ff8090; }
  .ai-feedback-text { font-size: 14px; line-height: 1.65; color: #c4cce8; }
  .ai-loading { display: flex; align-items: center; gap: 10px; font-size: 13px; color: var(--muted); margin-top: 12px; }
  @keyframes spin { to { transform: rotate(360deg); } }
  .spinner { width: 15px; height: 15px; border: 2px solid var(--border); border-top-color: var(--teal); border-radius: 50%; animation: spin 0.7s linear infinite; flex-shrink: 0; }

  /* ── Pitch deck section ── */
  .pitch-deck-section { margin-top: 16px; border-top: 1px solid var(--border); padding-top: 16px; }
  .pitch-deck-header { display: flex; align-items: center; justify-content: space-between; margin-bottom: 12px; flex-wrap: wrap; gap: 8px; }
  .pitch-deck-header h4 { font-family: 'Syne', sans-serif; font-size: 16px; color: var(--white); font-weight: 700; }
  .pitch-deck-header span { font-size: 12px; color: var(--muted); }
  .generate-deck-btn { background: var(--surface); color: var(--white); border: 1px solid var(--border); cursor: pointer; padding: 8px 16px; border-radius: 8px; font-family: 'Inter', sans-serif; font-size: 13px; font-weight: 600; transition: all 0.15s; display: flex; align-items: center; gap: 6px; white-space: nowrap; }
  .generate-deck-btn:hover:not(:disabled) { background: var(--blue); border-color: var(--blue); color: #fff; }
  .generate-deck-btn:disabled { opacity: 0.35; cursor: not-allowed; }
  .deck-loading { display: flex; align-items: center; gap: 10px; padding: 16px; background: var(--surface); border-radius: 8px; border: 1px solid var(--border); font-size: 13px; color: var(--muted); }
  .deck-error { padding: 12px 14px; background: rgba(255,80,80,0.1); border-radius: 8px; border-left: 3px solid var(--red); font-size: 13px; color: #ff8080; }

  /* ── Share modal ── */
  .share-section { margin-top: 1.25rem; }
  .share-section h4 { font-size: 12px; font-weight: 600; color: var(--muted); margin-bottom: 8px; text-transform: uppercase; letter-spacing: 0.5px; }
  .share-link-box { display: flex; gap: 8px; align-items: center; background: var(--surface); border-radius: 8px; border: 1px solid var(--border); padding: 10px 13px; margin-bottom: 12px; }
  .share-link-text { flex: 1; font-size: 12px; color: var(--muted); overflow: hidden; text-overflow: ellipsis; white-space: nowrap; font-family: 'JetBrains Mono', monospace; }
  .copy-btn { background: var(--blue); color: #fff; border: none; cursor: pointer; padding: 6px 14px; border-radius: 6px; font-size: 12px; font-family: 'Inter', sans-serif; white-space: nowrap; transition: all 0.15s; font-weight: 600; }
  .copy-btn:hover { background: #6b94ff; }
  .copy-btn.copied { background: var(--green); }
  .email-invite-row { display: flex; gap: 8px; }
  .email-invite-row input { flex: 1; padding: 9px 12px; border: 1px solid var(--border); border-radius: 8px; font-family: 'Inter', sans-serif; font-size: 13px; outline: none; background: var(--surface); color: var(--white); }
  .email-invite-row input::placeholder { color: var(--muted); }
  .email-invite-row input:focus { border-color: var(--blue); }
  .invite-btn { background: none; border: 1px solid var(--border); cursor: pointer; padding: 9px 14px; border-radius: 8px; font-size: 13px; font-family: 'Inter', sans-serif; transition: all 0.15s; color: var(--white); font-weight: 500; }
  .invite-btn:hover { border-color: rgba(255,255,255,0.25); background: var(--surface); }
  .invited-list { display: flex; flex-wrap: wrap; gap: 6px; margin-top: 8px; }
  .invited-chip { background: rgba(77,124,255,0.15); color: #7da4ff; font-size: 12px; padding: 3px 10px; border-radius: 20px; display: flex; align-items: center; gap: 5px; border: 1px solid rgba(77,124,255,0.3); }
  .invited-chip button { background: none; border: none; cursor: pointer; color: #7da4ff; font-size: 14px; line-height: 1; padding: 0; }

  ::-webkit-scrollbar { width: 5px; height: 5px; }
  ::-webkit-scrollbar-track { background: var(--navy); }
  ::-webkit-scrollbar-thumb { background: var(--border); border-radius: 4px; }
  ::-webkit-scrollbar-thumb:hover { background: var(--blue); }
`;

