// ── Slide Renderer ─────────────────────────────────────────────────────────────
function SlideRenderer({ slide }) {
  const s = { width: "100%", height: "100%" };
  const isDark = bg => {
    if (!bg || bg === "#ffffff" || bg === "#fff") return false;
    const hex = bg.replace("#", "");
    const r = parseInt(hex.slice(0,2), 16), g = parseInt(hex.slice(2,4), 16), b = parseInt(hex.slice(4,6), 16);
    return (r * 0.299 + g * 0.587 + b * 0.114) < 140;
  };
  const bodyColor  = slide.bg && isDark(slide.bg) ? "rgba(255,255,255,0.92)" : "#1a1a1a";
  const mutedColor = slide.bg && isDark(slide.bg) ? "rgba(255,255,255,0.6)"  : "#555";
  const metricBg   = slide.bg && isDark(slide.bg) ? "rgba(255,255,255,0.1)"  : "rgba(0,0,0,0.05)";
  const deltaColor = slide.bg && isDark(slide.bg) ? "#6eeda0" : "#16a34a";

  if (slide.layout === "title") return (
    <div style={{ ...s, background: slide.bg, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", padding: "10%" }}>
      <div style={{ width: 48, height: 5, background: slide.accent, borderRadius: 3, marginBottom: 24 }} />
      <h1 style={{ fontFamily: "'Syne',sans-serif", fontSize: 42, fontWeight: 800, color: "#fff", textAlign: "center", lineHeight: 1.12, marginBottom: 14, letterSpacing: "-0.5px" }}>{slide.title}</h1>
      {slide.subtitle && <p style={{ fontSize: 16, color: "rgba(255,255,255,0.75)", textAlign: "center", fontFamily: "'Inter',sans-serif" }}>{slide.subtitle}</p>}
    </div>
  );
  if (slide.layout === "metrics") return (
    <div style={{ ...s, background: slide.bg, padding: "7% 8% 6%" }}>
      <h2 style={{ fontFamily: "'Syne',sans-serif", fontSize: 26, fontWeight: 800, color: slide.accent, marginBottom: 20 }}>{slide.title}</h2>
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 14 }}>
        {slide.metrics.map((m, i) => (
          <div key={i} style={{ background: metricBg, borderRadius: 10, padding: "13px 16px", borderLeft: `3px solid ${slide.accent}` }}>
            <div style={{ fontSize: 11, color: mutedColor, marginBottom: 5, textTransform: "uppercase", letterSpacing: "0.7px", fontFamily: "'Inter',sans-serif", fontWeight: 600 }}>{m.label}</div>
            <div style={{ fontSize: 30, fontWeight: 700, color: slide.accent, fontFamily: "'Syne',sans-serif" }}>{m.value}</div>
            <div style={{ fontSize: 12, color: deltaColor, marginTop: 3, fontFamily: "'Inter',sans-serif", fontWeight: 500 }}>{m.delta}</div>
          </div>
        ))}
      </div>
    </div>
  );
  if (slide.layout === "roadmap") return (
    <div style={{ ...s, background: slide.bg, padding: "7% 8%" }}>
      <h2 style={{ fontFamily: "'Syne',sans-serif", fontSize: 26, fontWeight: 800, color: slide.accent, marginBottom: 20 }}>{slide.title}</h2>
      <div style={{ display: "flex", flexDirection: "column", gap: 11 }}>
        {slide.items.map((item, i) => (
          <div key={i} style={{ display: "flex", alignItems: "center", gap: 12 }}>
            <div style={{ width: 36, height: 36, borderRadius: 8, background: item.done ? slide.accent : metricBg, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 11, fontWeight: 700, color: item.done ? (isDark(slide.accent) ? "#fff" : "#1a1a1a") : mutedColor, flexShrink: 0, fontFamily: "'Inter',sans-serif" }}>{item.q}</div>
            <div style={{ flex: 1, height: 36, background: item.done ? (isDark(slide.bg) ? "rgba(255,255,255,0.12)" : "rgba(0,0,0,0.06)") : (isDark(slide.bg) ? "rgba(255,255,255,0.05)" : "rgba(0,0,0,0.03)"), borderRadius: 8, display: "flex", alignItems: "center", paddingLeft: 14, fontSize: 13, color: item.done ? bodyColor : mutedColor, fontWeight: item.done ? 600 : 400, fontFamily: "'Inter',sans-serif" }}>
              {item.label} {item.done && <span style={{ marginLeft: 8, fontSize: 11, color: deltaColor, fontWeight: 700 }}>✓</span>}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
  if (slide.layout === "bullets") return (
    <div style={{ ...s, background: slide.bg, padding: "7% 8%" }}>
      <h2 style={{ fontFamily: "'Syne',sans-serif", fontSize: 26, fontWeight: 800, color: slide.accent, marginBottom: 20 }}>{slide.title}</h2>
      <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
        {slide.bullets.map((b, i) => (
          <div key={i} style={{ display: "flex", alignItems: "flex-start", gap: 12 }}>
            <div style={{ width: 8, height: 8, borderRadius: "50%", background: slide.accent, flexShrink: 0, marginTop: 6 }} />
            <span style={{ fontSize: 14, color: bodyColor, lineHeight: 1.55, fontFamily: "'Inter',sans-serif" }}>{b}</span>
          </div>
        ))}
      </div>
    </div>
  );
  return null;
}

// ── Download helper ────────────────────────────────────────────────────────────
function downloadDeckAsHTML(slides, title) {
  const slideHTML = slides.map((slide, i) => {
    const isDark = bg => { if (!bg || bg === "#ffffff") return false; const hex = bg.replace("#",""); const r=parseInt(hex.slice(0,2),16),g=parseInt(hex.slice(2,4),16),b=parseInt(hex.slice(4,6),16); return (r*0.299+g*0.587+b*0.114)<140; };
    const bodyColor = isDark(slide.bg) ? "rgba(255,255,255,0.92)" : "#1a1a1a";
    const mutedColor = isDark(slide.bg) ? "rgba(255,255,255,0.6)" : "#555";
    const deltaColor = isDark(slide.bg) ? "#6eeda0" : "#16a34a";
    const metricBg = isDark(slide.bg) ? "rgba(255,255,255,0.1)" : "rgba(0,0,0,0.05)";

    let inner = "";
    if (slide.layout === "title") {
      inner = `<div style="display:flex;flex-direction:column;align-items:center;justify-content:center;height:100%;padding:10%;background:${slide.bg}"><div style="width:48px;height:5px;background:${slide.accent};border-radius:3px;margin-bottom:24px"></div><h1 style="font-family:sans-serif;font-size:42px;font-weight:800;color:#fff;text-align:center;line-height:1.12;margin-bottom:14px">${slide.title}</h1>${slide.subtitle ? `<p style="font-size:16px;color:rgba(255,255,255,0.75);text-align:center">${slide.subtitle}</p>` : ""}</div>`;
    } else if (slide.layout === "bullets") {
      const bullets = slide.bullets.map(b => `<div style="display:flex;gap:12px;align-items:flex-start;margin-bottom:12px"><div style="width:8px;height:8px;border-radius:50%;background:${slide.accent};flex-shrink:0;margin-top:6px"></div><span style="font-size:14px;color:${bodyColor};line-height:1.55">${b}</span></div>`).join("");
      inner = `<div style="padding:7% 8%;background:${slide.bg};height:100%;box-sizing:border-box"><h2 style="font-family:sans-serif;font-size:26px;font-weight:800;color:${slide.accent};margin-bottom:20px">${slide.title}</h2>${bullets}</div>`;
    } else if (slide.layout === "metrics") {
      const metrics = slide.metrics.map(m => `<div style="background:${metricBg};border-radius:10px;padding:13px 16px;border-left:3px solid ${slide.accent}"><div style="font-size:11px;color:${mutedColor};margin-bottom:5px;text-transform:uppercase">${m.label}</div><div style="font-size:30px;font-weight:700;color:${slide.accent}">${m.value}</div><div style="font-size:12px;color:${deltaColor};margin-top:3px">${m.delta}</div></div>`).join("");
      inner = `<div style="padding:7% 8%;background:${slide.bg};height:100%;box-sizing:border-box"><h2 style="font-family:sans-serif;font-size:26px;font-weight:800;color:${slide.accent};margin-bottom:20px">${slide.title}</h2><div style="display:grid;grid-template-columns:1fr 1fr;gap:14px">${metrics}</div></div>`;
    } else if (slide.layout === "roadmap") {
      const items = slide.items.map(item => `<div style="display:flex;align-items:center;gap:12px;margin-bottom:11px"><div style="width:36px;height:36px;border-radius:8px;background:${item.done ? slide.accent : metricBg};display:flex;align-items:center;justify-content:center;font-size:11px;font-weight:700;flex-shrink:0">${item.q}</div><div style="flex:1;height:36px;background:rgba(255,255,255,0.08);border-radius:8px;display:flex;align-items:center;padding-left:14px;font-size:13px;color:${bodyColor}">${item.label}${item.done ? " ✓" : ""}</div></div>`).join("");
      inner = `<div style="padding:7% 8%;background:${slide.bg};height:100%;box-sizing:border-box"><h2 style="font-family:sans-serif;font-size:26px;font-weight:800;color:${slide.accent};margin-bottom:20px">${slide.title}</h2>${items}</div>`;
    }
    return `<div class="slide" id="slide-${i}" style="display:${i===0?"block":"none"}">${inner}</div>`;
  }).join("\n");

  const html = `<!DOCTYPE html><html><head><meta charset="UTF-8"><title>${title}</title><style>*{box-sizing:border-box;margin:0;padding:0}body{font-family:sans-serif;background:#111;display:flex;flex-direction:column;align-items:center;justify-content:center;min-height:100vh;padding:20px}.deck{width:min(900px,100%);aspect-ratio:16/9;border-radius:12px;overflow:hidden;position:relative}.slide{width:100%;height:100%}.controls{display:flex;gap:16px;margin-top:16px;align-items:center}.btn{background:#1e2540;color:#eef1ff;border:1px solid #2a3356;padding:8px 20px;border-radius:8px;cursor:pointer;font-size:14px}.btn:hover{background:#2a3356}.counter{color:#8b95b8;font-size:14px}</style></head><body>
<div class="deck">${slideHTML}</div>
<div class="controls"><button class="btn" onclick="prev()">← Prev</button><span class="counter" id="ctr">1 / ${slides.length}</span><button class="btn" onclick="next()">Next →</button></div>
<script>let c=0;const s=document.querySelectorAll('.slide');function show(n){s.forEach((el,i)=>el.style.display=i===n?'block':'none');document.getElementById('ctr').textContent=(n+1)+' / '+s.length;}function next(){if(c<s.length-1){c++;show(c);}}function prev(){if(c>0){c--;show(c);}}</script>
</body></html>`;

  const blob = new Blob([html], { type: "text/html" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url; a.download = `${title.replace(/\s+/g, "_")}_deck.html`;
  a.click(); URL.revokeObjectURL(url);
}

// ── Inline Pitch Deck ──────────────────────────────────────────────────────────
function IdeaPitchDeck({ idea }) {
  const [slides, setSlides]       = useState(null);
  const [loading, setLoading]     = useState(false);
  const [error, setError]         = useState(null);
  const [current, setCurrent]     = useState(0);
  const [generated, setGenerated] = useState(false);

  const generate = async () => {
    setLoading(true); setError(null);
    try {
      const res = await fetch("http://localhost:3001/generate-deck", {
        method: "POST", headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ title: idea.title, category: idea.category, body: idea.body }),
      });
      const data = await res.json();
      if (data.error) throw new Error(data.error);
      setSlides(data.slides); setCurrent(0); setGenerated(true);
    } catch (e) {
      setError(e.message || "Failed to generate deck. Is the server running on port 3001?");
    }
    setLoading(false);
  };

  return (
    <div className="pitch-deck-section">
      <div className="pitch-deck-header">
        <h4>Pitch Deck</h4>
        {generated && <span>{slides?.length} slides generated</span>}
      </div>
      {!generated && !loading && <button className="generate-deck-btn" onClick={generate}>Generate Pitch Deck</button>}
      {loading && <div className="deck-loading"><div className="spinner" style={{ borderTopColor: "#00c8c8" }} />Assembling your pitch deck…</div>}
      {error && <div className="deck-error">{error}</div>}
      {slides && slides.length > 0 && (
        <>
          <div className="slide-viewer">
            <div className="slide-canvas"><div className="slide-inner"><SlideRenderer slide={slides[current]} /></div></div>
            <div className="slide-controls">
              <button className="slide-nav-btn" onClick={() => setCurrent(c => Math.max(0, c - 1))} disabled={current === 0}>← Prev</button>
              <div className="slide-dots">{slides.map((_, i) => <button key={i} className={`dot${i === current ? " active" : ""}`} onClick={() => setCurrent(i)} />)}</div>
              <button className="slide-nav-btn" onClick={() => setCurrent(c => Math.min(slides.length - 1, c + 1))} disabled={current === slides.length - 1}>Next →</button>
            </div>
            <div className="slide-thumbs">
              {slides.map((slide, i) => (
                <div key={i} className={`thumb${i === current ? " active" : ""}`} onClick={() => setCurrent(i)} style={{ background: slide.bg }}>
                  <div style={{ transform: "scale(0.22)", transformOrigin: "top left", width: "455px", height: "256px", pointerEvents: "none" }}><SlideRenderer slide={slide} /></div>
                </div>
              ))}
            </div>
            <div style={{ display: "flex", justifyContent: "flex-end", gap: 8, padding: "10px 16px", borderTop: "1px solid var(--border)", background: "var(--card)" }}>
              <button className="deck-download-btn" onClick={() => downloadDeckAsHTML(slides, idea.title)}>Download Deck</button>
              <button className="generate-deck-btn" onClick={generate} disabled={loading} style={{ fontSize: 13, padding: "5px 12px" }}>Regenerate</button>
            </div>
          </div>
        </>
      )}
    </div>
  );
}

// ── Auth Modal ─────────────────────────────────────────────────────────────────
function AuthModal({ onClose, onSignIn }) {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const handle = () => {
    if (!email.trim()) return setError("Enter your email.");
    if (!password.trim()) return setError("Password required.");
    const name = email.split("@")[0].replace(/[._]/g, " ").replace(/\b\w/g, c => c.toUpperCase());
    onSignIn({ email, name }); onClose();
  };
  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal" onClick={e => e.stopPropagation()}>
        <h2>Sign In to 4Tell</h2>
        <p className="modal-sub">Access your pitches, feedback, and decks</p>
        <div className="field"><label>Email</label><input type="email" placeholder="you@4tell.io" value={email} onChange={e => { setEmail(e.target.value); setError(""); }} onKeyDown={e => e.key === "Enter" && handle()} /></div>
        <div className="field"><label>Password</label><input type="password" placeholder="••••••••" value={password} onChange={e => { setPassword(e.target.value); setError(""); }} onKeyDown={e => e.key === "Enter" && handle()} /></div>
        {error && <div className="error-msg">{error}</div>}
        <div className="modal-actions">
          <button className="btn-secondary" onClick={onClose}>Cancel</button>
          <button className="btn-primary" onClick={handle}>Sign In</button>
        </div>
      </div>
    </div>
  );
}

// ── Edit Idea Modal ────────────────────────────────────────────────────────────
function EditIdeaModal({ idea, onClose, onSave }) {
  const [title, setTitle]       = useState(idea.title);
  const [category, setCategory] = useState(idea.category);
  const [body, setBody]         = useState(idea.body);
  const [visibility, setVis]    = useState(idea.visibility);
  const categoryColors = { Product: true, Design: true, Marketing: true, Engineering: true, Operations: true };

  const handleSave = () => {
    if (!title.trim() || !body.trim()) return;
    onSave({ ...idea, title, category, body, visibility });
    onClose();
  };

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal tall" onClick={e => e.stopPropagation()}>
        <h2>Edit Pitch</h2>
        <p className="modal-sub">Update your idea details below</p>
        <div className="field"><label>Title</label><input value={title} onChange={e => setTitle(e.target.value)} placeholder="Your idea title…" /></div>
        <div className="field">
          <label>Category</label>
          <select value={category} onChange={e => setCategory(e.target.value)}>
            {Object.keys(categoryColors).map(c => <option key={c}>{c}</option>)}
          </select>
        </div>
        <div className="field"><label>Description</label><textarea value={body} onChange={e => setBody(e.target.value)} rows={5} placeholder="Describe your idea…" /></div>
        <div className="field">
          <label>Visibility</label>
          <div style={{ display: "flex", gap: 8 }}>
            {["public", "private"].map(v => (
              <button key={v} onClick={() => setVis(v)} style={{ flex: 1, padding: "10px", borderRadius: 8, border: `1px solid ${visibility === v ? "var(--blue)" : "var(--border)"}`, background: visibility === v ? "rgba(77,124,255,0.12)" : "var(--surface)", color: "var(--white)", cursor: "pointer", fontFamily: "'Inter',sans-serif", fontSize: 13, fontWeight: visibility === v ? 600 : 400, transition: "all 0.15s" }}>
                {v === "public" ? "Public" : "Private"}
              </button>
            ))}
          </div>
        </div>
        <div className="modal-actions">
          <button className="btn-secondary" onClick={onClose}>Cancel</button>
          <button className="btn-primary" onClick={handleSave}>Save Changes</button>
        </div>
      </div>
    </div>
  );
}

// ── Share Modal ────────────────────────────────────────────────────────────────
function ShareModal({ item, onClose }) {
  const isPrivate = item.visibility === "private";
  const [copied, setCopied] = useState(false);
  const [emailInput, setEmailInput] = useState("");
  const [invited, setInvited] = useState([]);
  const link = `https://4tell.io/ideas/${item.id}`;
  const copyLink = () => { setCopied(true); setTimeout(() => setCopied(false), 2000); };
  const addEmail = () => {
    const e = emailInput.trim();
    if (e && !invited.includes(e)) setInvited(prev => [...prev, e]);
    setEmailInput("");
  };
  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal wide" onClick={e => e.stopPropagation()}>
        <h2>Share Pitch</h2>
        <p className="modal-sub">{isPrivate ? `"${item.title}" — private. Invite collaborators below.` : `"${item.title}" — public. Anyone with the link can view.`}</p>
        <div className="share-section">
          <h4>Link</h4>
          <div className="share-link-box">
            <span className="share-link-text">{link}</span>
            <button className={`copy-btn${copied ? " copied" : ""}`} onClick={copyLink}>{copied ? "Copied!" : "Copy"}</button>
          </div>
        </div>
        {isPrivate && (
          <div className="share-section">
            <h4>Invite by Email</h4>
            <div className="email-invite-row">
              <input type="email" placeholder="colleague@example.com" value={emailInput} onChange={e => setEmailInput(e.target.value)} onKeyDown={e => e.key === "Enter" && addEmail()} />
              <button className="invite-btn" onClick={addEmail}>Invite</button>
            </div>
            {invited.length > 0 && (
              <div className="invited-list">
                {invited.map((e, i) => (
                  <div key={i} className="invited-chip">{e}<button onClick={() => setInvited(prev => prev.filter((_, j) => j !== i))}>×</button></div>
                ))}
              </div>
            )}
          </div>
        )}
        <div className="modal-actions"><button className="btn-primary" onClick={onClose}>Done</button></div>
      </div>
    </div>
  );
}

// ── Deck Viewer (Reviewer) ─────────────────────────────────────────────────────
function DeckViewer({ deck, user, onBack }) {
  const [current, setCurrent] = useState(0);
  const [mode, setMode] = useState("view");
  const [allComments, setAllComments] = useState([
    { slideIdx: 0, text: "Great opening — very clean layout.", author: "Alex T.", id: 1 },
    { slideIdx: 1, text: "Revenue number is strong. Consider adding YoY context.", author: "Sam R.", id: 2 },
  ]);
  const [commentText, setCommentText] = useState("");
  const slideComments = allComments.filter(c => c.slideIdx === current);
  const addComment = () => {
    if (!commentText.trim() || !user) return;
    setAllComments(prev => [...prev, { slideIdx: current, text: commentText, author: user.name, id: Date.now() }]);
    setCommentText("");
  };
  return (
    <div>
      <button className="back-btn" onClick={onBack}>← Back to Decks</button>
      <div style={{ display: "flex", alignItems: "flex-start", justifyContent: "space-between", marginBottom: "1.5rem", flexWrap: "wrap", gap: 12 }}>
        <div>
          <h1 style={{ fontFamily: "'Syne',sans-serif", fontSize: 28, marginBottom: 8, color: "var(--white)", fontWeight: 800 }}>{deck.title}</h1>
          <div className="pill-row">
            <span className={`tag ${deck.category === "Fundraising" ? "amber" : deck.category === "Strategy" ? "green" : "indigo"}`}>{deck.category}</span>
            <span style={{ fontSize: 12, color: "var(--muted)" }}>by {deck.author}</span>
            <span style={{ fontSize: 12, color: "var(--muted)" }}>· {allComments.length} comment{allComments.length !== 1 ? "s" : ""}</span>
          </div>
        </div>
        <div className="mode-toggle">
          <button className={`mode-tab${mode === "view" ? " active" : ""}`} onClick={() => setMode("view")}>View</button>
          <button className={`mode-tab${mode === "comment" ? " active" : ""}`} onClick={() => setMode("comment")}>Review</button>
        </div>
      </div>
      <div className="slide-viewer">
        {mode === "comment" && <div className="comment-mode-bar">Review mode — commenting on slide {current + 1}</div>}
        <div className="slide-canvas"><div className="slide-inner"><SlideRenderer slide={deck.slides[current]} /></div></div>
        <div className="slide-controls">
          <button className="slide-nav-btn" onClick={() => setCurrent(c => Math.max(0, c - 1))} disabled={current === 0}>← Prev</button>
          <div className="slide-dots">{deck.slides.map((_, i) => <button key={i} className={`dot${i === current ? " active" : ""}`} onClick={() => setCurrent(i)} />)}</div>
          <button className="slide-nav-btn" onClick={() => setCurrent(c => Math.min(deck.slides.length - 1, c + 1))} disabled={current === deck.slides.length - 1}>Next →</button>
        </div>
        <div className="slide-thumbs">
          {deck.slides.map((slide, i) => {
            const cnt = allComments.filter(c => c.slideIdx === i).length;
            return (
              <div key={i} style={{ position: "relative" }}>
                <div className={`thumb${i === current ? " active" : ""}`} onClick={() => setCurrent(i)} style={{ background: slide.bg }}>
                  <div style={{ transform: "scale(0.22)", transformOrigin: "top left", width: "455px", height: "256px", pointerEvents: "none" }}><SlideRenderer slide={slide} /></div>
                </div>
                {cnt > 0 && <div style={{ position: "absolute", top: -4, right: -4, background: "#ff4040", color: "#fff", fontSize: 9, fontWeight: 700, width: 16, height: 16, borderRadius: "50%", display: "flex", alignItems: "center", justifyContent: "center", border: "1.5px solid #0a0f3c" }}>{cnt}</div>}
              </div>
            );
          })}
        </div>
        <div style={{ display: "flex", justifyContent: "flex-end", padding: "10px 16px", borderTop: "1px solid var(--border)", background: "var(--card)" }}>
          <button className="deck-download-btn" onClick={() => downloadDeckAsHTML(deck.slides, deck.title)}>Download Deck</button>
        </div>
        <div className="comment-panel">
          <div className="comment-panel-header"><h4>Slide {current + 1} Comments ({slideComments.length})</h4></div>
          {slideComments.length > 0 && (
            <div className="comment-list">
              {slideComments.map(c => (
                <div key={c.id} className="comment-item">
                  <div className="avatar" style={{ marginTop: 2 }}>{c.author.split(" ").map(n => n[0]).join("").slice(0, 2)}</div>
                  <div className="comment-body"><div className="comment-author">{c.author}</div><div className="comment-text">{c.text}</div></div>
                </div>
              ))}
            </div>
          )}
          {user ? (
            <div className="comment-input-row">
              <input placeholder={`Comment on slide ${current + 1}…`} value={commentText} onChange={e => setCommentText(e.target.value)} onKeyDown={e => e.key === "Enter" && addComment()} />
              <button className="comment-send-btn" onClick={addComment}>Post</button>
            </div>
          ) : (
            <div style={{ padding: "10px 16px 14px", fontSize: 12, color: "var(--muted)" }}>Sign in to leave comments.</div>
          )}
        </div>
      </div>
    </div>
  );
}

// ── Reviewer Page ──────────────────────────────────────────────────────────────
function ReviewerPage({ user, onSignInClick }) {
  const [query, setQuery] = useState("");
  const [selectedDeck, setSelectedDeck] = useState(null);
  const filtered = DECKS.filter(d => [d.title, d.author, d.category].some(s => s.toLowerCase().includes(query.toLowerCase())));
  if (!user) return (
    <div className="page">
      <div className="page-header"><h1>Reviewer Mode</h1><p>Browse pitch decks and leave slide-by-slide feedback.</p></div>
      <div className="locked-gate"><h3>Sign In Required</h3><p>You must be signed in to access reviewer mode.</p><button className="btn-primary" style={{ width: "auto", padding: "10px 28px" }} onClick={onSignInClick}>Sign In</button></div>
    </div>
  );
  if (selectedDeck) return <div className="page"><DeckViewer deck={selectedDeck} user={user} onBack={() => setSelectedDeck(null)} /></div>;
  return (
    <div className="page">
      <div className="page-header">
        <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 6 }}>
          <h1 style={{ marginBottom: 0 }}>Reviewer Mode</h1>
          <span className="reviewer-badge">Reviewer</span>
        </div>
        <p>Browse pitch decks and leave slide-by-slide feedback.</p>
      </div>
      <div className="search-bar"><span className="search-icon">⌕</span><input placeholder="Search by title, author, or category…" value={query} onChange={e => setQuery(e.target.value)} /></div>
      {filtered.length === 0
        ? <div style={{ textAlign: "center", padding: "3rem", color: "var(--muted)", fontSize: 14 }}>No decks match "{query}"</div>
        : <div className="deck-grid">{filtered.map(deck => (
            <div key={deck.id} className="deck-card" onClick={() => setSelectedDeck(deck)}>
              <div className="deck-thumb" style={{ background: deck.slides[0].bg }}>
                <div style={{ transform: "scale(0.38)", transformOrigin: "top left", width: "263px", height: "148px", pointerEvents: "none" }}><SlideRenderer slide={deck.slides[0]} /></div>
              </div>
              <div className="deck-info">
                <div className="deck-title">{deck.title}</div>
                <div className="deck-meta"><span className={`tag ${deck.category === "Fundraising" ? "amber" : deck.category === "Strategy" ? "green" : "indigo"}`}>{deck.category}</span>{deck.author}</div>
              </div>
            </div>
          ))}</div>
      }
    </div>
  );
}

