// ── Ideas Page ─────────────────────────────────────────────────────────────────
const categoryColors = {
  Product:     { bg: "rgba(26,58,255,0.2)",  color: "#6699ff", border: "#1a3aff" },
  Design:      { bg: "rgba(0,200,200,0.15)", color: "#00c8c8", border: "#00c8c8" },
  Marketing:   { bg: "rgba(0,200,100,0.15)", color: "#00c864", border: "#00c864" },
  Engineering: { bg: "rgba(0,229,255,0.12)", color: "#00e5ff", border: "#00e5ff" },
  Operations:  { bg: "rgba(255,180,0,0.15)", color: "#ffb400", border: "#ffb400" },
};

const defaultIdeas = [
  { id: "i1", title: "Dark mode for dashboard", category: "Design",    body: "Many users work late and would benefit from a dark mode option.", author: "Alex T.", visibility: "public",  feedbackType: "constructive", feedback: "This is a highly requested feature — prioritizing accessibility and user comfort is a great angle. Consider framing it around reduced eye strain rather than just aesthetics to strengthen the case.", feedbackLoading: false },
  { id: "i2", title: "Weekly digest email",     category: "Marketing", body: "Automated weekly summary of activity sent to all users.",         author: "Sam R.",  visibility: "private", feedbackType: "friendly",     feedback: "Love this idea — it keeps people engaged without requiring them to log in every day. A little nudge like this can do wonders for retention!", feedbackLoading: false },
];

function IdeasPage({ user, onSignInClick }) {
  const [title, setTitle]               = useState("");
  const [category, setCategory]         = useState("Product");
  const [body, setBody]                 = useState("");
  const [visibility, setVis]            = useState("public");
  const [feedbackType, setFeedbackType] = useState("constructive");
  const [submitting, setSubmitting]     = useState(false);
  const [submitted, setSubmitted]       = useState(false);
  const [ideas, setIdeas]               = useState(defaultIdeas);
  const [shareItem, setShareItem]       = useState(null);
  const [editItem, setEditItem]         = useState(null);

  const handleSubmit = async () => {
    if (!title.trim() || !body.trim() || submitting) return;
    setSubmitting(true);
    const tempId = `i${Date.now()}`;
    const newIdea = { id: tempId, title, category, body, author: user.name, visibility, feedbackType, feedback: null, feedbackLoading: true };
    setIdeas(prev => [newIdea, ...prev]);
    setTitle(""); setBody(""); setCategory("Product"); setVis("public"); setFeedbackType("constructive");
    setSubmitted(true);
    setTimeout(() => setSubmitted(false), 4000);
    try {
      const response = await fetch("http://localhost:3001/feedback", {
        method: "POST", headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ title, category, body, feedbackType }),
      });
      const data = await response.json();
      setIdeas(prev => prev.map(idea => idea.id === tempId ? { ...idea, feedback: data.feedback, feedbackLoading: false } : idea));
    } catch {
      setIdeas(prev => prev.map(idea => idea.id === tempId ? { ...idea, feedback: "AI feedback unavailable — make sure your server is running on port 3001.", feedbackLoading: false } : idea));
    }
    setSubmitting(false);
  };

  const handleSaveEdit = (updated) => {
    setIdeas(prev => prev.map(i => i.id === updated.id ? updated : i));
  };

  if (!user) return (
    <div className="page">
      <div className="page-header"><h1>Submit a Pitch</h1><p>Share your idea and get instant AI feedback.</p></div>
      <div className="locked-gate"><h3>Sign In Required</h3><p>You must be signed in to submit pitches and view the board.</p><button className="btn-primary" style={{ width: "auto", padding: "10px 28px" }} onClick={onSignInClick}>Sign In</button></div>
    </div>
  );

  return (
    <div className="page">
      {shareItem && <ShareModal item={shareItem} onClose={() => setShareItem(null)} />}
      {editItem  && <EditIdeaModal idea={editItem} onClose={() => setEditItem(null)} onSave={handleSaveEdit} />}

      <div className="page-header"><h1>Submit a Pitch</h1><p>Drop your idea. Get AI feedback. Build a deck.</p></div>

      <div className="visibility-toggle">
        <button className={`vis-btn${visibility === "public" ? " selected" : ""}`} onClick={() => setVis("public")}>
          <div className="vis-btn-label">Public</div>
          <div className="vis-btn-desc">Visible to everyone on 4Tell</div>
        </button>
        <button className={`vis-btn${visibility === "private" ? " selected" : ""}`} onClick={() => setVis("private")}>
          <div className="vis-btn-label">Private</div>
          <div className="vis-btn-desc">Invite-only access</div>
        </button>
      </div>

      <div className="idea-form">
        <div className="form-field"><label>Pitch Title</label><input type="text" placeholder="Give your idea a clear title…" value={title} onChange={e => setTitle(e.target.value)} /></div>
        <div className="form-field">
          <label>Category</label>
          <select value={category} onChange={e => setCategory(e.target.value)}>
            {Object.keys(categoryColors).map(c => <option key={c}>{c}</option>)}
          </select>
        </div>
        <div className="form-field"><label>Description</label><textarea placeholder="Describe your idea — the problem it solves, how it works…" value={body} onChange={e => setBody(e.target.value)} /></div>

        <div style={{ marginBottom: "1.25rem" }}>
          <span className="feedback-type-label">AI Feedback Style</span>
          <div className="feedback-type-grid">
            {FEEDBACK_TYPES.map(ft => (
              <button key={ft.key} className={`feedback-type-btn${feedbackType === ft.key ? " selected" : ""}`} onClick={() => setFeedbackType(ft.key)}>
                <span className="ftb-icon"><FeedbackIcon iconKey={ft.iconKey} size={22} color={feedbackType === ft.key ? "#00c8c8" : "rgba(240,244,255,0.45)"} /></span>
                <span className="ftb-name">{ft.name}</span>
                <span className="ftb-desc">{ft.desc}</span>
              </button>
            ))}
          </div>
        </div>

        <button className="submit-btn" onClick={handleSubmit} disabled={submitting}>
          {submitting ? "Submitting…" : `Submit ${visibility === "private" ? "Privately" : "to 4Tell"}`}
        </button>
        {submitted && (
          <div className="success-card">
            <h3>Pitch Submitted!</h3>
            <p>Nice work, {user.name.split(" ")[0]} — Herbie is generating your {FEEDBACK_LABELS[feedbackType]?.label} feedback…</p>
          </div>
        )}
      </div>

      <div className="ideas-list">
        <h3>Pitch Board</h3>
        {ideas.map(idea => {
          const c = categoryColors[idea.category] || { bg: "rgba(255,255,255,0.05)", color: "#aaa", border: "#555" };
          const fb = FEEDBACK_LABELS[idea.feedbackType] || FEEDBACK_LABELS.constructive;
          const isOwn = idea.author === user?.name;
          return (
            <div key={idea.id} className="idea-card">
              <div className="idea-card-top">
                <div>
                  <div className="pill-row" style={{ marginBottom: 4 }}>
                    <span className="category-badge" style={{ background: c.bg, color: c.color, border: `1px solid ${c.border}` }}>{idea.category}</span>
                    <span className={`tag ${idea.visibility === "private" ? "gray" : "green"}`}>{idea.visibility === "private" ? "Private" : "Public"}</span>
                  </div>
                  <div className="idea-card-meta">by {idea.author}</div>
                </div>
                <div className="card-action-row">
                  {isOwn && (
                    <button className="edit-icon-btn" onClick={() => setEditItem(idea)}>Edit</button>
                  )}
                  <button className="share-icon-btn" onClick={() => setShareItem(idea)}>Share</button>
                </div>
              </div>
              <div className="idea-card-title">{idea.title}</div>
              <div className="idea-card-body">{idea.body}</div>

              {idea.feedbackLoading && (
                <div className="ai-loading"><div className="spinner" /><img src={HERBIE_SRC} alt="Herbie" style={{ width: 24, height: 24, objectFit: "contain" }} />Herbie is analyzing…</div>
              )}
              {idea.feedback && !idea.feedbackLoading && (
                <div className={`ai-feedback ${idea.feedbackType}`}>
                  <img src={HERBIE_SRC} alt="Herbie AI" className="ai-bot-img" />
                  <div className="ai-feedback-content">
                    <div className="ai-feedback-label">
                      <FeedbackIcon iconKey={fb.iconKey} size={14} color="currentColor" />
                      {fb.label} Analysis
                    </div>
                    <div className="ai-feedback-text">{idea.feedback}</div>
                  </div>
                </div>
              )}

              <IdeaPitchDeck idea={idea} />
            </div>
          );
        })}
      </div>
    </div>
  );
}

// ── Nav ────────────────────────────────────────────────────────────────────────
function Nav({ page, setPage, user, onSignInClick, onSignOut }) {
  return (
    <nav className="nav">
      <div className="nav-brand" onClick={() => setPage("home")} style={{ cursor: "pointer" }}>
        <img src={LOGO_SRC} alt="4Tell logo" />
        4Tell
      </div>
      <div style={{ display: "flex", alignItems: "center", gap: 2 }}>
        <div className="nav-links">
          <button className={`nav-btn${page === "home"     ? " active" : ""}`} onClick={() => setPage("home")}>Home</button>
          <button className={`nav-btn${page === "reviewer" ? " active" : ""}`} onClick={() => setPage("reviewer")}>Reviewer</button>
          <button className={`nav-btn${page === "ideas"    ? " active" : ""}`} onClick={() => setPage("ideas")}>Submit Pitch</button>
        </div>
        {user ? (
          <div style={{ display: "flex", alignItems: "center", gap: 10, marginLeft: 10 }}>
            <div className="user-chip">
              <div className="avatar">{user.name.split(" ").map(n => n[0]).join("").slice(0, 2)}</div>
              <span>{user.name.split(" ")[0]}</span>
            </div>
            <button className="sign-btn out" onClick={onSignOut}>Sign Out</button>
          </div>
        ) : (
          <button className="sign-btn" onClick={onSignInClick} style={{ marginLeft: 10 }}>Sign In</button>
        )}
      </div>
    </nav>
  );
}

// ── Root App ───────────────────────────────────────────────────────────────────
export default function App() {
  const [page, setPage]         = useState("home");
  const [user, setUser]         = useState(null);
  const [showAuth, setShowAuth] = useState(false);

  return (
    <>
      <style>{styles}</style>
      <Nav page={page} setPage={setPage} user={user} onSignInClick={() => setShowAuth(true)} onSignOut={() => setUser(null)} />
      {page === "home"     && <HomePage onSignInClick={() => setShowAuth(true)} setPage={setPage} />}
      {page === "reviewer" && <ReviewerPage user={user} onSignInClick={() => setShowAuth(true)} />}
      {page === "ideas"    && <IdeasPage    user={user} onSignInClick={() => setShowAuth(true)} />}
      {showAuth && <AuthModal onClose={() => setShowAuth(false)} onSignIn={u => setUser(u)} />}
    </>
  );
}